# ---------------------------------------------------------------------------
# Synthesizer
# ---------------------------------------------------------------------------

def synthesize_questions(
    count: int = 200,
    tricky_ratio: float = 0.45,
    seed: int = 42,
) -> list[dict[str, Any]]:
    """
    Generate synthetic questions across all 22 themes.

    Args:
        count: Total number of questions to generate.
        tricky_ratio: Target fraction of tricky questions.
        seed: RNG seed for reproducibility.

    Returns:
        List of question dicts matching the ParsedQuestion schema.
    """
    rng = random.Random(seed)
    questions_per_theme = count // len(THEME_SLUGS)
    remainder = count % len(THEME_SLUGS)
    tricky_per_theme = int(questions_per_theme * tricky_ratio)

    all_questions: list[dict[str, Any]] = []

    pbar = tqdm(THEME_SLUGS, desc="Synthesizing", unit="theme")
    for i, theme_slug in enumerate(pbar):
        n = questions_per_theme + (1 if i < remainder else 0)
        n_tricky = tricky_per_theme + (1 if i < remainder else 0)
        n_normal = n - n_tricky

        templates = QUESTION_TEMPLATES[theme_slug]
        tricky_templates = [t for t in templates if t[3] is not None]
        normal_templates = [t for t in templates if t[3] is None]

        # Adjust tricky count if no tricky templates available
        if not tricky_templates:
            n_normal = n
            n_tricky = 0
        elif not normal_templates:
            n_tricky = n
            n_normal = 0

        # Ensure we have enough templates
        if tricky_templates and n_tricky > 0:
            if len(tricky_templates) < n_tricky:
                tricky_templates = tricky_templates * (n_tricky // len(tricky_templates) + 1)
        if normal_templates and n_normal > 0:
            if len(normal_templates) < n_normal:
                normal_templates = normal_templates * (n_normal // len(normal_templates) + 1)

        # Select tricky templates
        selected_tricky = [tricky_templates[rng.randint(0, len(tricky_templates) - 1)] for _ in range(n_tricky)] if tricky_templates and n_tricky > 0 else []
        selected_normal = [normal_templates[rng.randint(0, len(normal_templates) - 1)] for _ in range(n_normal)] if normal_templates and n_normal > 0 else []
        selected = selected_tricky + selected_normal
        rng.shuffle(selected)

        for prompt, answer, explanation, tricky_pattern in selected:
            variation = rng.choice(["", " Additionally,", " Furthermore,", " Note that,", " Remember that,"])
            varied_prompt = prompt + variation if variation and rng.random() < 0.3 else prompt

            is_tricky = tricky_pattern is not None
            all_questions.append({
                "prompt_en": varied_prompt,
                "answer_en": answer,
                "explanation_en": explanation,
                "theme_slug": theme_slug,
                "source_url": "https://jp-drivers-test-trainer.internal/synthesized",
                "license": "synthesized",
                "attribution": "JP Drivers Test Trainer — AI-synthesized from official rule knowledge",
                "raw_text": varied_prompt,
                "tricky": is_tricky,
                "tricky_pattern": tricky_pattern,
                "difficulty": 4 if is_tricky else 2,
            })

    return all_questions


def save_synthesized(questions: list[dict[str, Any]]) -> Path:
    """Save synthesized questions to raw_scrapes/synthesized/."""
    RAW_DIR.mkdir(parents=True, exist_ok=True)
    output_path = RAW_DIR / "synthesized_questions.json"
    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(questions, f, indent=2, ensure_ascii=False)
    print(f"Saved {len(questions)} synthesized questions to {output_path}")
    return output_path


def main() -> int:
    import argparse
    parser = argparse.ArgumentParser(description="Synthesize JP driver's test questions")
    parser.add_argument("--count", type=int, default=660, help="Number of questions to generate")
    parser.add_argument("--tricky-ratio", type=float, default=0.50, help="Target tricky ratio")
    parser.add_argument("--seed", type=int, default=42, help="RNG seed")
    args = parser.parse_args()

    questions = synthesize_questions(
        count=args.count,
        tricky_ratio=args.tricky_ratio,
        seed=args.seed,
    )
    save_synthesized(questions)

    # Stats
    tricky_count = sum(1 for q in questions if q["tricky"])
    theme_counts: dict[str, int] = {}
    for q in questions:
        theme_counts[q["theme_slug"]] = theme_counts.get(q["theme_slug"], 0) + 1

    print(f"\nStats:")
    print(f"  Total: {len(questions)}")
    print(f"  Tricky: {tricky_count} ({tricky_count/len(questions)*100:.1f}%)")
    print(f"  Themes: {len(theme_counts)}")
    for slug, cnt in sorted(theme_counts.items()):
        print(f"    {slug}: {cnt}")

    return 0


if __name__ == "__main__":
    import sys
    sys.exit(main())
